UPDATE BRD_POST_MST
   SET view_cnt = view_cnt + 1
 WHERE post_no = #{postNo}

UPDATE BRD_POST_MST
   SET del_yn = 'Y',
       del_ts = NOW()
 WHERE post_no   = #{postNo}
   AND member_no = #{memberNo}
   AND del_yn    = 'N'

mapper.select:
SELECT comment_no, post_no, like_cnt, dislike_cnt
  FROM BRD_POST_COMMENT
 WHERE comment_no = #{commentNo}

mapper.update:
UPDATE BRD_POST_COMMENT
   SET del_yn = 'Y'
 WHERE comment_no = #{commentNo}
   AND member_no  = #{memberNo}
   AND del_yn     = 'N'

UPDATE BRD_POST_MST
   SET comment_cnt = (
           SELECT COUNT(*)
             FROM BRD_POST_COMMENT
            WHERE post_no = #{postNo}
              AND del_yn  = 'N'
       )
 WHERE post_no = #{postNo}

