DELETE FROM BRD_POST_REACTION
 WHERE post_typ_cd = '1'
   AND post_no     = #{postNo}
   AND comment_no  = 0
   AND member_no   = #{memberNo}

mapper.update:
UPDATE BRD_POST_MST
   SET like_cnt = (
           SELECT COUNT(*) FROM BRD_POST_REACTION
            WHERE post_no = #{postNo} AND post_typ_cd = '1' AND reaction_typ_cd = '1'
       ),
       dislike_cnt = (
           SELECT COUNT(*) FROM BRD_POST_REACTION
            WHERE post_no = #{postNo} AND post_typ_cd = '1' AND reaction_typ_cd = '2'
       )
 WHERE post_no = #{postNo}

